const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  host: process.env.DB_HOST || 'localhost',
  port: process.env.DB_PORT || 5432,
  database: process.env.DB_NAME || 'coupon_system',
  user: process.env.DB_USER || 'postgres',
  password: process.env.DB_PASSWORD || 'postgres',
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

async function initializeDatabase() {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS coupons (
        id SERIAL PRIMARY KEY,
        code VARCHAR(50) UNIQUE NOT NULL,
        discount_type VARCHAR(20) NOT NULL,
        discount_value DECIMAL(10, 2) NOT NULL,
        min_purchase_amount DECIMAL(10, 2) DEFAULT 0,
        max_uses INTEGER,
        current_uses INTEGER DEFAULT 0,
        expires_at TIMESTAMP,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        CHECK (discount_type IN ('percentage', 'fixed')),
        CHECK (discount_value > 0),
        CHECK (current_uses >= 0),
        CHECK (max_uses IS NULL OR max_uses > 0)
      );
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS coupon_redemptions (
        id SERIAL PRIMARY KEY,
        coupon_id INTEGER NOT NULL REFERENCES coupons(id),
        user_id INTEGER NOT NULL,
        order_id VARCHAR(100) UNIQUE NOT NULL,
        discount_amount DECIMAL(10, 2) NOT NULL,
        redeemed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        UNIQUE(coupon_id, order_id)
      );
    `);

    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_coupons_code ON coupons(code);
    `);

    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_redemptions_user_coupon ON coupon_redemptions(user_id, coupon_id);
    `);

    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_redemptions_order ON coupon_redemptions(order_id);
    `);

  } finally {
    client.release();
  }
}

async function redeemCoupon(userId, couponCode, orderId, purchaseAmount) {
  const client = await pool.connect();
  
  try {
    await client.query('BEGIN');
    
    const idempotencyCheck = await client.query(
      'SELECT discount_amount FROM coupon_redemptions WHERE order_id = $1',
      [orderId]
    );
    
    if (idempotencyCheck.rows.length > 0) {
      await client.query('COMMIT');
      return {
        success: true,
        alreadyRedeemed: true,
        discountAmount: parseFloat(idempotencyCheck.rows[0].discount_amount),
        message: 'Coupon already redeemed for this order'
      };
    }

    const updateResult = await client.query(`
      UPDATE coupons
      SET current_uses = current_uses + 1
      WHERE code = $1
        AND (expires_at IS NULL OR expires_at > NOW())
        AND (max_uses IS NULL OR current_uses < max_uses)
        AND $2 >= min_purchase_amount
      RETURNING id, discount_type, discount_value, current_uses, max_uses
    `, [couponCode, purchaseAmount]);

    if (updateResult.rows.length === 0) {
      await client.query('ROLLBACK');
      
      const couponCheck = await client.query(
        'SELECT expires_at, max_uses, current_uses, min_purchase_amount FROM coupons WHERE code = $1',
        [couponCode]
      );
      
      if (couponCheck.rows.length === 0) {
        return { success: false, error: 'Invalid coupon code' };
      }
      
      const coupon = couponCheck.rows[0];
      
      if (coupon.expires_at && new Date(coupon.expires_at) <= new Date()) {
        return { success: false, error: 'Coupon has expired' };
      }
      
      if (coupon.max_uses && coupon.current_uses >= coupon.max_uses) {
        return { success: false, error: 'Coupon usage limit reached' };
      }
      
      if (purchaseAmount < parseFloat(coupon.min_purchase_amount)) {
        return { 
          success: false, 
          error: `Minimum purchase amount of ${coupon.min_purchase_amount} required` 
        };
      }
      
      return { success: false, error: 'Coupon cannot be applied' };
    }

    const coupon = updateResult.rows[0];
    let discountAmount;

    if (coupon.discount_type === 'percentage') {
      discountAmount = (purchaseAmount * parseFloat(coupon.discount_value)) / 100;
    } else {
      discountAmount = Math.min(parseFloat(coupon.discount_value), purchaseAmount);
    }

    discountAmount = Math.round(discountAmount * 100) / 100;

    await client.query(`
      INSERT INTO coupon_redemptions (coupon_id, user_id, order_id, discount_amount)
      VALUES ($1, $2, $3, $4)
    `, [coupon.id, userId, orderId, discountAmount]);

    await client.query('COMMIT');

    return {
      success: true,
      discountAmount: discountAmount,
      finalAmount: purchaseAmount - discountAmount,
      message: 'Coupon applied successfully'
    };

  } catch (error) {
    await client.query('ROLLBACK');
    
    if (error.code === '23505') {
      const retryCheck = await client.query(
        'SELECT discount_amount FROM coupon_redemptions WHERE order_id = $1',
        [orderId]
      );
      
      if (retryCheck.rows.length > 0) {
        return {
          success: true,
          alreadyRedeemed: true,
          discountAmount: parseFloat(retryCheck.rows[0].discount_amount),
          message: 'Coupon already redeemed for this order'
        };
      }
    }
    
    throw error;
  } finally {
    client.release();
  }
}

async function createCoupon(code, discountType, discountValue, options = {}) {
  const client = await pool.connect();
  
  try {
    const result = await client.query(`
      INSERT INTO coupons (code, discount_type, discount_value, min_purchase_amount, max_uses, expires_at)
      VALUES ($1, $2, $3, $4, $5, $6)
      RETURNING *
    `, [
      code,
      discountType,
      discountValue,
      options.minPurchaseAmount || 0,
      options.maxUses || null,
      options.expiresAt || null
    ]);

    return { success: true, coupon: result.rows[0] };
  } catch (error) {
    if (error.code === '23505') {
      return { success: false, error: 'Coupon code already exists' };
    }
    throw error;
  } finally {
    client.release();
  }
}

async function getUserRedemptions(userId) {
  const result = await pool.query(`
    SELECT 
      cr.id,
      cr.order_id,
      cr.discount_amount,
      cr.redeemed_at,
      c.code,
      c.discount_type,
      c.discount_value
    FROM coupon_redemptions cr
    JOIN coupons c ON cr.coupon_id = c.id
    WHERE cr.user_id = $1
    ORDER BY cr.redeemed_at DESC
  `, [userId]);

  return result.rows;
}

async function getCouponStats(couponCode) {
  const result = await pool.query(`
    SELECT 
      c.*,
      COUNT(cr.id) as total_redemptions,
      COALESCE(SUM(cr.discount_amount), 0) as total_discount_given
    FROM coupons c
    LEFT JOIN coupon_redemptions cr ON c.id = cr.coupon_id
    WHERE c.code = $1
    GROUP BY c.id
  `, [couponCode]);

  if (result.rows.length === 0) {
    return { success: false, error: 'Coupon not found' };
  }

  return { success: true, stats: result.rows[0] };
}

app.post('/api/coupons', async (req, res) => {
  try {
    const { code, discountType, discountValue, minPurchaseAmount, maxUses, expiresAt } = req.body;

    if (!code || !discountType || !discountValue) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    if (!['percentage', 'fixed'].includes(discountType)) {
      return res.status(400).json({ error: 'Invalid discount type' });
    }

    const result = await createCoupon(code, discountType, discountValue, {
      minPurchaseAmount,
      maxUses,
      expiresAt
    });

    if (!result.success) {
      return res.status(400).json({ error: result.error });
    }

    res.status(201).json(result.coupon);
  } catch (error) {
    console.error('Error creating coupon:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.post('/api/redeem', async (req, res) => {
  try {
    const { userId, couponCode, orderId, purchaseAmount } = req.body;

    if (!userId || !couponCode || !orderId || !purchaseAmount) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    if (purchaseAmount <= 0) {
      return res.status(400).json({ error: 'Invalid purchase amount' });
    }

    const result = await redeemCoupon(userId, couponCode, orderId, purchaseAmount);

    if (!result.success) {
      return res.status(400).json({ error: result.error });
    }

    res.json(result);
  } catch (error) {
    console.error('Error redeeming coupon:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/api/users/:userId/redemptions', async (req, res) => {
  try {
    const userId = parseInt(req.params.userId);
    const redemptions = await getUserRedemptions(userId);
    res.json(redemptions);
  } catch (error) {
    console.error('Error fetching redemptions:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/api/coupons/:code/stats', async (req, res) => {
  try {
    const result = await getCouponStats(req.params.code);
    
    if (!result.success) {
      return res.status(404).json({ error: result.error });
    }

    res.json(result.stats);
  } catch (error) {
    console.error('Error fetching coupon stats:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

const PORT = process.env.PORT || 3000;

async function startServer() {
  try {
    await initializeDatabase();
    app.listen(PORT, () => {
      console.log(`Coupon redemption system running on port ${PORT}`);
    });
  } catch (error) {
    console.error('Failed to start server:', error);
    process.exit(1);
  }
}

startServer();

module.exports = { redeemCoupon, createCoupon, getUserRedemptions, getCouponStats };